207: fn truncate_str(s: &str, chars: usize) -> (&str, bool) {
208:     if chars == 0 {
209:         return (s, false);
210:     }
211:     s.char_indices()
212:         .enumerate()
213:         .find_map(|(idx, (offset, _))| {
214:             if idx == chars {
215:                 Some((&s[..offset], true))
216:             } else {
217:                 None
218:             }
219:         })
220:         .unwrap_or((s, false))
221: }
