4: pub trait StringRepr: AsRef<str> {}
5: 
6: impl StringRepr for str {}
7: impl StringRepr for String {}
8: impl<'a> StringRepr for Cow<'a, str> {}
9: impl<T: StringRepr + ?Sized> StringRepr for &T {}
