59: #[test]
60: fn test_object() {
61:     macro_rules! print_object {
62:         ($expr:expr, $mode:ident) => {{
63:             use $crate::print::PrintObject;
64:             #[allow(unused_mut)]
65:             let mut _tmp = ($expr,);
66:             _tmp.print_object($crate::print::PrintMode::$mode)
67:                 .map(|x| x.to_string())
