75:     impl DoNotCallMe {
76:         #[allow(unused)]
77:         fn print_object(&self, mode: PrintMode) {
78:             panic!("never call me");
79:         }
80:     }
81: 
82:     assert_eq!(
83:         print_object!(&DoNotCallMe, Default).as_deref(),
84:         Some("similar_asserts::print::test_object::DoNotCallMe")
85:     );
